      "subtask": "Reorder filtered results by ascending price",
      "atomics": [
        "Click sort dropdown menu at top of results",
        "Select 'Price: Low to High' or ascending price sort option",
        "Observe products reorder with lowest-priced unit at top"
      ]
    },
    {
      "subtask": "Extract product name and price from the first (cheapest) result",
      "atomics": [
        "Read product name/model text from first list item",
        "Read price value displayed for first product",
        "Verify power output specification field shows ≥600W"
      ]
    }
  ],
  "global_atomics": [
    "Confirm final answer contains product name, exact price, and wattage meets 600W requirement",
    "Scan top 3-5 results to ensure no lower-priced 600W+ alternative exists"
  ]
